import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote", () => {
    it.todo("returns empty results for empty steps");
    it.todo("quotes a single sword for a new customer (base + first insurance + processing fee)");
    it.todo("quotes other main item types (amulet, staff, potion)");
    it.todo("sums multiple main items in one quote");
    it.todo("quotes a single component (rune) at component pricing");
    it.todo("bundles 3 alike components at the special base premium of 60 G");
    it.todo("does not bundle 3 components of different kinds");
    it.todo("applies 50% cursed surcharge per item");
    it.todo("applies 30% enchantment surcharge for enchantment >= 5");
    it.todo("applies 20% loyalty discount for customers with >= 2 years");
    it.todo("applies 15% subsequent-contract discount to quotes after the first");
    it.todo("rounds the final premium up to whole G (in MHPCO favor)");
  });

  describe("Claim", () => {
    it.todo("applies 100 G deductible to a basic claim");
    it.todo("reimburses 50% for items with enchantment >= 8 (after deductible)");
    it.todo("fully reimburses items made of dragon material (after deductible)");
    it.todo("returns 0 payout when deductible exceeds reimbursable amount");
  });
});

