type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] } | { op: "claim" };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const quote = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
  return Math.ceil(base * 1.1) + 5;
};

const processStep = (step: Step): unknown =>
  step.op === "quote" ? { premium: quote(step.items) } : {};

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map(processStep),
});

