import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote", () => {
    it("returns empty results for empty steps", () => {
      const result = runScenario({ customer: { yearsWithMHPCO: 0 }, steps: [] });
      expect(result).toEqual({ results: [] });
    });
    it("quotes a single sword for a new customer (base + first insurance + processing fee)", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("quotes other main item types (amulet, staff, potion)", () => {
      const customer = { yearsWithMHPCO: 0 };
      const amulet = runScenario({
        customer,
        steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
      });
      expect(amulet).toEqual({ results: [{ premium: 71 }] });
      const staff = runScenario({
        customer,
        steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }] }],
      });
      expect(staff).toEqual({ results: [{ premium: 93 }] });
      const potion = runScenario({
        customer,
        steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
      });
      expect(potion).toEqual({ results: [{ premium: 49 }] });
    });
    it.todo("sums multiple main items in one quote");
    it.todo("quotes a single component (rune) at component pricing");
    it.todo("bundles 3 alike components at the special base premium of 60 G");
    it.todo("does not bundle 3 components of different kinds");
    it.todo("applies 50% cursed surcharge per item");
    it.todo("applies 30% enchantment surcharge for enchantment >= 5");
    it.todo("applies 20% loyalty discount for customers with >= 2 years");
    it.todo("applies 15% subsequent-contract discount to quotes after the first");
    it.todo("rounds the final premium up to whole G (in MHPCO favor)");
  });

  describe("Claim", () => {
    it.todo("applies 100 G deductible to a basic claim");
    it.todo("reimburses 50% for items with enchantment >= 8 (after deductible)");
    it.todo("fully reimburses items made of dragon material (after deductible)");
    it.todo("returns 0 payout when deductible exceeds reimbursable amount");
  });
});

