const COMPONENT_BUNDLE_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune"]);

const itemBase = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

const countsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  return counts;
};

const baseForType = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type)) {
    const bundles = Math.floor(count / 3);
    const singles = count % 3;
    return bundles * COMPONENT_BUNDLE_PRICE + singles * (BASE_PREMIUM[type] ?? 0);
  }
  return count * (BASE_PREMIUM[type] ?? 0);
};

const quote = (items: Item[]): number => {
  const counts = countsByType(items);
  let base = 0;
  for (const [type, count] of counts) base += baseForType(type, count);
  return ceilToWholeG(base * FIRST_INSURANCE_MULTIPLIER) + PROCESSING_FEE;
};

