  [...groupByType(items)].reduce(
    (sum, [type, group]) => sum + baseForGroup(type, group),
    0,
  );

const quote = (items: Item[], customer: Scenario["customer"]): number => {
  const adjusted = baseForItems(items) * customerMultiplier(customer) * FIRST_INSURANCE_MULTIPLIER;
  return ceilToWholeG(adjusted) + PROCESSING_FEE;
};

const processStep = (step: Step, customer: Scenario["customer"]): unknown =>
  step.op === "quote" ? { premium: quote(step.items, customer) } : {};

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map((step) => processStep(step, scenario.customer)),
});

